from langchain_community.vectorstores import Chroma
from langchain_openai import OpenAIEmbeddings
from langchain_core.documents import Document
import uuid, json

embeddings = OpenAIEmbeddings()
vectorstore = Chroma(embedding_function=embeddings)

# Raw content store: element_id → {type, content/path}
raw_store: dict[str, dict] = {}

def index_multimodal_elements(elements: list[dict]) -> None:
    docs = []
    for el in elements:
        el_id = str(uuid.uuid4())
        el_type = el["type"]

        if el_type == "text":
            embed_text = el["text"]
            raw_store[el_id] = {"type": "text", "content": el["text"]}
        elif el_type == "image":
            embed_text = el["caption"]  # embed caption, not raw pixels
            raw_store[el_id] = {"type": "image", "path": el["image_path"], "caption": el["caption"]}
        elif el_type == "table":
            embed_text = el["text"]
            raw_store[el_id] = {"type": "table", "content": el["text"]}
        else:
            continue

        docs.append(Document(
            page_content=embed_text,
            metadata={"element_id": el_id, "type": el_type, "page": el.get("page")},
        ))

    vectorstore.add_documents(docs)

