from langchain_openai import ChatOpenAI
import base64, httpx

judge_llm = ChatOpenAI(model="gpt-4o", temperature=0)

def evaluate_image_fidelity(image_b64: str, answer: str) -> dict:
    """Ask a VLM judge whether the answer is faithful to the image."""
    messages = [
        {"role": "user", "content": [
            {"type": "text", "text": (
                "You are an evaluator. Given the image and an AI answer, score:\n"
                "1. image_used (bool): did the answer reference anything visible in the image?\n"
                "2. hallucination (bool): did the answer add details NOT visible in the image?\n"
                "Return JSON only."
            )},
            {"type": "image_url", "image_url": {"url": f"data:image/jpeg;base64,{image_b64}"}},
            {"type": "text", "text": f"Answer: {answer}"}
        ]}
    ]
    result = judge_llm.invoke(messages).content
    import json
    return json.loads(result)

# Usage
img_b64 = base64.b64encode(open("retrieved_fig.jpg", "rb").read()).decode()
score = evaluate_image_fidelity(img_b64, "The encoder block contains 6 attention heads.")
print(score)  # {"image_used": true, "hallucination": false}
